function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    let P = new Array(n).fill(1);

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            P[idx] = (P[idx] * vi) % MOD;
            idx += ki;
        }
    }

    let xor = 0;
    for (let i = 0; i < n; i++) {
        xor ^= (nums[i] * P[i]) % MOD;
    }

    return xor;
}
